/**
 * @name Zip Slip - ZipEntry name flows to File constructor without path traversal check
 * @description ZipEntry.getName() result used directly in File construction, enabling path traversal (Zip Slip)
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // ZipEntry.getName() calls
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get() / Path.resolve()
    exists(MethodCall mc |
      (
        (mc.getMethod().hasName("get") and mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths")) or
        (mc.getMethod().hasName("resolve") and mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path"))
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Zip Slip: ZipEntry name flows to file path construction at $@.", sink.getNode(), "this location"

/**
 * @name Zip Slip - confirmed inter-procedural taint from ZipEntry name to File (no canonical guard)
 * @description ZipEntry.getName() taint flows inter-procedurally to File construction without canonical path check
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-confirmed
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-023
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor with the entry name as argument
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  // Block flow if canonical path check is performed (getCanonicalPath followed by startsWith)
  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getCanonicalPath") and
      node.asExpr() = mc
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("toRealPath") and
      node.asExpr() = mc
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where
  ZipSlipFlow::flowPath(source, sink) and
  // Only in zt-zip source files
  sink.getNode().getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.zeroturnaround.zip%")
select sink.getNode(), source, sink,
  "Zip Slip: ZipEntry name flows to File construction without canonical path verification - path traversal possible."
